1	/**
2	 * Collection Report Details Page Content Component
3	 *
4	 * Handles all state management and data fetching for the collection report detail page.
5	 *
6	 * Features:
7	 * - Machine Metrics tab: View individual machine collection data
8	 * - Location Metrics tab: View location-level aggregated metrics
9	 * - SAS Metrics Compare tab: Compare SAS times and metrics
10	 * - Issue detection and fixing
11	 * - Search and filter capabilities
12	 * - Pagination
13	 * - Responsive design for mobile and desktop
14	 */
15	
16	'use client';
17	
18	import { CollectionReportDetailsCollectionsTable } from '@/components/CMS/collectionReport/details/CollectionReportDetailsCollectionsTable';
19	import CollectionReportDetailsLocationMetricsTab from '@/components/CMS/collectionReport/details/CollectionReportDetailsLocationMetricsTab';
20	import CollectionReportDetailsSasCompareTab from '@/components/CMS/collectionReport/details/CollectionReportDetailsSasCompareTab';
21	import CollectionReportEditCollectionModal from '@/components/CMS/collectionReport/modals/CollectionReportEditCollectionModal';
22	import PageLayout from '@/components/shared/layout/PageLayout';
23	import { Button } from '@/components/shared/ui/button';
24	import {
25	  DropdownMenu,
26	  DropdownMenuContent,
27	  DropdownMenuItem,
28	  DropdownMenuTrigger,
29	} from '@/components/shared/ui/dropdown-menu';
30	import NotFoundError from '@/components/shared/ui/errors/NotFoundError';
31	import NetworkError from '@/components/shared/ui/errors/NetworkError';
32	import UnauthorizedError from '@/components/shared/ui/errors/UnauthorizedError';
33	import { CollectionReportSkeleton } from '@/components/shared/ui/skeletons/CollectionReportDetailSkeletons';
34	import RetryLoadingBar from '@/components/shared/ui/RetryLoadingBar';
35	import { downloadCollectionReport } from '@/lib/utils/export/collectionReportExport';
36	import {
37	  animateDesktopTabTransition,
38	  calculateLocationTotal,
39	} from '@/lib/helpers/collectionReport';
40	import { getLocationsWithMachines } from '@/lib/helpers/collectionReport/fetching';
41	import { useCollectionReportDetailsData } from '@/lib/hooks/collectionReport/useCollectionReportDetailsData';
42	import { useUserStore } from '@/lib/store/userStore';
43	import type { CollectionReportLocationWithMachines } from '@/lib/types/api';
44	import { formatCurrency } from '@/lib/utils/currency';
45	import { formatDateWithOrdinal } from '@/lib/utils/date/formatting';
46	import { ArrowLeft, Download, FileSpreadsheet, FileText, Pencil, RefreshCw, Share2 } from 'lucide-react';
47	import { toast } from 'sonner';
48	import Link from 'next/link';
49	import { useCallback, useEffect, useState } from 'react';
50	
51	export default function CollectionReportDetailsPageContent() {
52	  // ============================================================================
53	  // State & Hooks
54	  // ============================================================================
55	  const hook = useCollectionReportDetailsData();
56	  const user = useUserStore(state => state.user);
57	
58	  // Only developer, owner and admin can edit
59	  const canEdit = !!(
60	    user?.roles &&
61	    (user.roles.includes('developer') ||
62	      user.roles.includes('admin') ||
63	      user.roles.includes('owner'))
64	  );
65	
66	  const [showEditModal, setShowEditModal] = useState(false);
67	  const [editLocations, setEditLocations] = useState<
68	    CollectionReportLocationWithMachines[]
69	  >([]);
70	  const [loadingLocations, setLoadingLocations] = useState(false);
71	
72	  // ============================================================================
73	  // Handlers
74	  // ============================================================================
75	  const handleShare = async () => {
76	    const shareUrl = typeof window !== 'undefined' ? window.location.href : '';
77	    try {
78	      if (navigator.share) {
79	        await navigator.share({ title: 'Collection Report', url: shareUrl });
80	      } else {
81	        await navigator.clipboard.writeText(shareUrl);
82	        toast.success('Link copied to clipboard');
83	      }
84	    } catch (err) {
85	      const isAbort = err instanceof Error && err.name === 'AbortError';
86	      if (!isAbort) toast.error('Could not share link');
87	    }
88	  };
89	
90	  // ============================================================================
91	  // Table Interaction & Edit Handlers
92	  // ============================================================================
93	  const handleOpenEdit = useCallback(async () => {
94	    if (loadingLocations) return;
95	    setLoadingLocations(true);
96	    try {
97	      const locs = await getLocationsWithMachines();
98	      setEditLocations(locs);
99	    } catch {
100	      // fall back to empty — the modal will still load its own data
101	      setEditLocations([]);
102	    } finally {
103	      setLoadingLocations(false);
104	    }
105	    setShowEditModal(true);
106	  }, [loadingLocations]);
107	
108	  const {
109	    reportData,
110	    loading,
111	    error,
112	    activeTab,
113	    searchTerm,
114	    sortField,
115	    sortDirection,
116	    paginatedMetricsData,
117	    machineTotalPages,
118	    machinePage,
119	    tabContentRef,
120	    collections,
121	    errorDetail,
122	    isRetrying,
123	    attempt,
124	    maxRetries,
125	    retryCountdown,
126	    setMachinePage,
127	    setSearchTerm,
128	    handleSort,
129	    handleTabChange,
130	    handleRefresh,
131	  } = hook;
132	
133	  // ============================================================================
134	  // Effects
135	  // ============================================================================
136	  // Animate tab transitions on desktop
137	  useEffect(() => {
138	    animateDesktopTabTransition(tabContentRef);
139	  }, [activeTab, tabContentRef]);
140	
141	  // ============================================================================
142	  // Computed & Render
143	  // ============================================================================
144	  const locationTotal = reportData ? calculateLocationTotal(collections) : 0;
145	  //red = negative values, green = positive values
146	  const textColorClass = locationTotal < 0 ? 'text-red-600' : 'text-green-600';
147	  if (loading) {
148	    return (
149	      <div className="w-full">
150	        <div className="px-2 pt-4 lg:px-6">
151	          <RetryLoadingBar
152	            isRetrying={isRetrying}
153	            retryCountdown={retryCountdown}
154	            attempt={attempt}
155	            maxRetries={maxRetries}
156	            expectedDurationMs={30000}
157	          />
158	        </div>
159	        <CollectionReportSkeleton />
160	      </div>
161	    );
162	  }
163	
164	  // Handle error states
165	  if (error === 'UNAUTHORIZED') {
166	    return (
167	      <UnauthorizedError
168	        title="Access Denied"
169	        message="You are not authorized to view this collection report."
170	        resourceType="report"
171	        customBackText="Back to Collection Reports"
172	        customBackHref="/collection-report"
173	      />
174	    );
175	  }
176	
177	  if (error === 'CONNECTION') {
178	    return (
179	      <NetworkError
180	        title="Report is taking too long to load"
181	        message="The request timed out before the report finished loading. This is usually a slow connection or an unusually heavy report — the report itself most likely exists. Please try again."
182	        onRetry={handleRefresh}
183	        showRetry={true}
184	        errorDetails={errorDetail || undefined}
185	      />
186	    );
187	  }
188	
189	  if (error || !reportData) {
190	    return (
191	      <NotFoundError
192	        title="Collection Report Not Found"
193	        message={
194	          error && error !== 'UNAUTHORIZED'
195	            ? error
196	            : 'The requested collection report could not be found.'
197	        }
198	        resourceType="report"
199	        showRetry={false}
200	        customBackText="Back to Collection Reports"
201	        customBackHref="/collection-report"
202	      />
203	    );
204	  }
205	
206	  const TabButton = ({
207	    label,
208	  }: {
209	    label: 'Machine Metrics' | 'Location Metrics' | 'SAS Metrics Compare';
210	  }) => (
211	    <button
212	      onClick={() => !loading && handleTabChange(label)}
213	      disabled={loading}
214	      className={`w-full rounded-md px-4 py-3 text-left text-sm font-medium transition-colors ${
215	        activeTab === label
216	          ? 'bg-buttonActive text-white'
217	          : 'text-gray-700 hover:bg-gray-100'
218	      } ${loading ? 'cursor-not-allowed opacity-50' : ''}`}
219	    >
220	      {label}
221	    </button>
222	  );
223	
224	  return (
225	    <>
226	      <PageLayout
227	        headerProps={{
228	          containerPaddingMobile: 'px-4 py-8 lg:px-0 lg:py-0',
229	          disabled: loading,
230	        }}
231	        hideOptions={true}
232	        hideLicenceeFilter={true}
233	        mainClassName="flex flex-col flex-1 w-full max-w-full"
234	        showToaster={false}
235	        onRefresh={handleRefresh}
236	        refreshing={loading}
237	      >
238	        {/* Header Section (Desktop Only): Back button, title */}
239	        <div className="hidden px-2 pt-6 lg:block lg:px-6">
240	          <div className="mb-6 flex items-center justify-between">
241	            <div className="flex items-center gap-3">
242	              <Link href="/collection-report">
243	                <Button
244	                  variant="ghost"
245	                  className="rounded-full border border-gray-200 p-2 hover:bg-gray-100"
246	                >
247	                  <ArrowLeft size={18} className="h-5 w-5" />
248	                </Button>
249	              </Link>
250	              <h1 className="text-2xl font-bold">Collection Report Details</h1>
251	            </div>
252	
253	            <div className="flex items-center gap-3">
254	              <DropdownMenu>
255	                <DropdownMenuTrigger asChild>
256	                  <Button
257	                    variant="outline"
258	                    className="flex items-center gap-2"
259	                    title="Export report data"
260	                  >
261	                    <Download className="h-4 w-4" />
262	                    <span className="hidden sm:inline">Export</span>
263	                  </Button>
264	                </DropdownMenuTrigger>
265	                <DropdownMenuContent align="end">
266	                  <DropdownMenuItem
267	                    onClick={() => downloadCollectionReport(reportData, 'csv')}
268	                    className="cursor-pointer"
269	                  >
270	                    <FileText className="mr-2 h-4 w-4" />
271	                    Export as CSV
272	                  </DropdownMenuItem>
273	                  <DropdownMenuItem
274	                    onClick={() => downloadCollectionReport(reportData, 'json')}
275	                    className="cursor-pointer"
276	                  >
277	                    <FileSpreadsheet className="mr-2 h-4 w-4" />
278	                    Export as JSON
279	                  </DropdownMenuItem>
280	                </DropdownMenuContent>
281	              </DropdownMenu>
282	
283	              <Button
284	                variant="outline"
285	                className="flex items-center gap-2"
286	                onClick={handleShare}
287	                title="Share this report"
288	              >
289	                <Share2 className="h-4 w-4" />
290	                <span className="hidden sm:inline">Share</span>
291	              </Button>
292	
293	              <Button
294	                variant="outline"
295	                className="flex items-center gap-2"
296	                onClick={handleRefresh}
297	                disabled={loading}
298	                title="Refresh Report Data"
299	              >
300	                <RefreshCw
301	                  className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`}
302	                />
303	                <span className="hidden sm:inline">Refresh</span>
304	              </Button>
305	
306	              {canEdit && (
307	                <Button
308	                  variant="outline"
309	                  className="flex items-center gap-2"
310	                  onClick={handleOpenEdit}
311	                  disabled={loadingLocations}
312	                >
313	                  <Pencil size={16} />
314	                  {loadingLocations ? 'Loading…' : 'Edit Report'}
315	                </Button>
316	              )}
317	            </div>
318	          </div>
319	        </div>
320	
321	        {/* Mobile Back Button & Actions */}
322	        <div className="flex items-center justify-between px-2 pt-4 lg:hidden">
323	          <Link href="/collection-report" className="inline-block">
324	            <Button
325	              variant="ghost"
326	              className="rounded-full border border-gray-200 p-2 hover:bg-gray-100"
327	            >
328	              <ArrowLeft size={18} className="h-5 w-5" />
329	            </Button>
330	          </Link>
331	
332	          <div className="flex items-center gap-2">
333	            <DropdownMenu>
334	              <DropdownMenuTrigger asChild>
335	                <Button
336	                  variant="outline"
337	                  size="sm"
338	                  className="h-9 w-9 p-0"
339	                  title="Export report data"
340	                >
341	                  <Download className="h-4 w-4" />
342	                </Button>
343	              </DropdownMenuTrigger>
344	              <DropdownMenuContent align="end">
345	                <DropdownMenuItem
346	                  onClick={() => downloadCollectionReport(reportData, 'csv')}
347	                  className="cursor-pointer"
348	                >
349	                  <FileText className="mr-2 h-4 w-4" />
350	                  Export as CSV
351	                </DropdownMenuItem>
352	                <DropdownMenuItem
353	                  onClick={() => downloadCollectionReport(reportData, 'json')}
354	                  className="cursor-pointer"
355	                >
356	                  <FileSpreadsheet className="mr-2 h-4 w-4" />
357	                  Export as JSON
358	                </DropdownMenuItem>
359	              </DropdownMenuContent>
360	            </DropdownMenu>
361	
362	            <Button
363	              variant="outline"
364	              size="sm"
365	              className="h-9 w-9 p-0"
366	              onClick={handleShare}
367	              title="Share this report"
368	            >
369	              <Share2 className="h-4 w-4" />
370	            </Button>
371	
372	            <Button
373	              variant="outline"
374	              size="sm"
375	              className="h-9 w-9 p-0"
376	              onClick={handleRefresh}
377	              disabled={loading}
378	              title="Refresh Report Data"
379	            >
380	              <RefreshCw
381	                className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`}
382	              />
383	            </Button>
384	
385	            {canEdit && (
386	              <Button
387	                variant="outline"
388	                size="sm"
389	                className="flex h-9 items-center gap-2 px-3"
390	                onClick={handleOpenEdit}
391	                disabled={loadingLocations}
392	              >
393	                <Pencil size={14} />
394	                <span className="text-xs font-semibold">
395	                  {loadingLocations ? 'Loading…' : 'Edit Report'}
396	                </span>
397	              </Button>
398	            )}
399	          </div>
400	        </div>
401	
402	        {/* Report Header Section: Location name, report ID, and financial summary */}
403	        <div className="px-2 pb-6 pt-2 lg:px-6 lg:pt-4">
404	          <div className="rounded-lg bg-white py-4 shadow lg:border-t-4 lg:border-lighterBlueHighlight lg:bg-container lg:py-8">
405	            <div className="px-4 py-2 text-center lg:py-4">
406	              <div className="mb-2 text-xs text-gray-500 lg:hidden">
407	                COLLECTION REPORT
408	              </div>
409	              <h1 className="mb-2 text-2xl font-bold text-gray-800 lg:text-4xl">
410	                {reportData.locationName}
411	              </h1>
412	              <p className="mb-2 text-sm text-gray-600 lg:text-base">
413	                {/* TODO Change to Compound field later to a more understandable report ID rather than using _id*/}
414	                Report ID: {reportData.reportId}
415	              </p>
416	              <div className="mb-4 space-y-1 text-sm font-medium text-gray-600 lg:text-base">
417	                <p>
418	                  Collector:{' '}
419	                  {reportData.collectorName || reportData.collector || '—'}
420	                </p>
421	                <p>
422	                  Created:{' '}
423	                  {reportData.createdAt
424	                    ? formatDateWithOrdinal(reportData.createdAt)
425	                    : '—'}
426	                </p>
427	                {(reportData.timeframeStart || reportData.timeframeEnd) && (
428	                  <p>
429	                    Timeframe:{' '}
430	                    {reportData.timeframeStart
431	                      ? formatDateWithOrdinal(reportData.timeframeStart)
432	                      : '—'}{' '}
433	                    →{' '}
434	                    {reportData.timeframeEnd
435	                      ? formatDateWithOrdinal(reportData.timeframeEnd)
436	                      : '—'}
437	                  </p>
438	                )}
439	              </div>
440	              <p className={`text-lg font-semibold`}>
441	                Collection Report Machine Total Gross:{' '}
442	                <span className={textColorClass}>
443	                  {formatCurrency(locationTotal)}
444	                </span>
445	              </p>
446	            </div>
447	          </div>
448	        </div>
449	
450	        {/* Desktop Content Section: Sidebar navigation (1/4 width) and main content (3/4 width) */}
451	        <div className="hidden px-2 pb-6 lg:flex lg:flex-row lg:space-x-6 lg:px-6">
452	          {/* Sidebar */}
453	          <div className="mb-6 lg:mb-0 lg:w-1/4">
454	            <div className="space-y-2 rounded-lg bg-white p-3 shadow">
455	              <h3 className="mb-4 text-lg font-semibold text-gray-800">
456	                Report Sections
457	              </h3>
458	              <div className="space-y-2">
459	                <TabButton label="Machine Metrics" />
460	                <TabButton label="Location Metrics" />
461	                <TabButton label="SAS Metrics Compare" />
462	              </div>
463	            </div>
464	          </div>
465	
466	          {/* Main Content */}
467	          <div className="lg:w-3/4" ref={tabContentRef}>
468	            {activeTab === 'Machine Metrics' && (
469	              <CollectionReportDetailsCollectionsTable
470	                metrics={reportData.machineMetrics || []}
471	                paginatedMetrics={paginatedMetricsData}
472	                searchTerm={searchTerm}
473	                onSearchChange={setSearchTerm}
474	                sortField={sortField}
475	                sortDirection={sortDirection}
476	                onSort={handleSort}
477	                currentPage={machinePage}
478	                totalPages={machineTotalPages}
479	                onPageChange={setMachinePage}
480	                useNetGross={reportData.useNetGross || false}
481	              />
482	            )}
483	
484	            {activeTab === 'Location Metrics' && (
485	              <CollectionReportDetailsLocationMetricsTab
486	                reportData={reportData}
487	              />
488	            )}
489	
490	            {activeTab === 'SAS Metrics Compare' && (
491	              <CollectionReportDetailsSasCompareTab reportData={reportData} />
492	            )}
493	          </div>
494	        </div>
495	
496	        {/* Mobile Content Section: Select dropdown and content */}
497	        <div className="px-2 pb-6 lg:hidden">
498	          {/* Mobile Navigation Select */}
499	          <div className="mb-6">
500	            <select
501	              value={activeTab}
502	              onChange={e =>
503	                handleTabChange(e.target.value as typeof activeTab)
504	              }
505	              className="w-full cursor-pointer rounded-lg border border-gray-300 bg-white px-4 py-3 text-base font-semibold text-gray-700 shadow-sm focus:border-buttonActive focus:ring-buttonActive"
506	              disabled={loading}
507	            >
508	              <option value="Machine Metrics">Machine Metrics</option>
509	              <option value="Location Metrics">Location Metrics</option>
510	              <option value="SAS Metrics Compare">SAS Metrics Compare</option>
511	            </select>
512	          </div>
513	
514	          {/* Mobile Content */}
515	          <div className="space-y-4">
516	            {activeTab === 'Machine Metrics' && (
517	              <CollectionReportDetailsCollectionsTable
518	                metrics={reportData.machineMetrics || []}
519	                paginatedMetrics={paginatedMetricsData}
520	                searchTerm={searchTerm}
521	                onSearchChange={setSearchTerm}
522	                sortField={sortField}
523	                sortDirection={sortDirection}
524	                onSort={handleSort}
525	                currentPage={machinePage}
526	                totalPages={machineTotalPages}
527	                onPageChange={setMachinePage}
528	                useNetGross={reportData.useNetGross || false}
529	              />
530	            )}
531	
532	            {activeTab === 'Location Metrics' && (
533	              <CollectionReportDetailsLocationMetricsTab
534	                reportData={reportData}
535	              />
536	            )}
537	
538	            {activeTab === 'SAS Metrics Compare' && (
539	              <CollectionReportDetailsSasCompareTab reportData={reportData} />
540	            )}
541	          </div>
542	        </div>
543	      </PageLayout>
544	
545	      {/* Edit Collection Report Modal — developer / admin only */}
546	      {canEdit && showEditModal && reportData && (
547	        <CollectionReportEditCollectionModal
548	          show={showEditModal}
549	          onClose={() => setShowEditModal(false)}
550	          reportId={reportData.reportId}
551	          locations={editLocations}
552	          onRefresh={handleRefresh}
553	        />
554	      )}
555	    </>
556	  );
557	}
