1	/**
2	 * useCollectionReportDetailsData Hook
3	 *
4	 * Manages all state and logic for the collection report detail page.
5	 *
6	 * Features:
7	 * - Data fetching for report details and machine collections
8	 * - Sorting, searching, and pagination for machine metrics
9	 * - SAS time issue detection and auto-fix logic
10	 * - Report fixing/finalization handlers
11	 * - URL synchronization for tab state
12	 */
13	
14	'use client';
15	
16	// ============================================================================
17	// External Dependencies
18	// ============================================================================
19	
20	import { fetchCollectionReportById } from '@/lib/helpers/collectionReport';
21	import { fetchCollectionsByLocationReportId } from '@/lib/helpers/collections';
22	import { useRequestWithRetry } from '@/lib/hooks/data/useRequestWithRetry';
23	import type { CollectionReportData, MachineMetric } from '@/lib/types/api';
24	import type { CollectionDocument } from '@/lib/types/collection';
25	import { validateCollectionReportData } from '@/lib/utils/validation';
26	import { useParams, useRouter, useSearchParams } from 'next/navigation';
27	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
28	
29	// ============================================================================
30	// Type Definitions
31	// ============================================================================
32	
33	type TabType = 'Machine Metrics' | 'Location Metrics' | 'SAS Metrics Compare';
34	
35	// ============================================================================
36	// Constants
37	// ============================================================================
38	
39	const ITEMS_PER_PAGE = 20;
40	
41	/**
42	 * Per-attempt request timeout before the request is aborted and retried.
43	 * The report's meter aggregation can legitimately take ~30s, so allow generous headroom —
44	 * a true timeout means a slow/hung connection, not a missing report.
45	 */
46	const ATTEMPT_TIMEOUT_MS = 60000;
47	
48	// ============================================================================
49	// Helper Functions
50	// ============================================================================
51	
52	/**
53	 * Sorts machines alphabetically with numeric awareness
54	 * Groups machines like "Machine 1, Machine 2, Machine 10" correctly
55	 */
56	function sortMachinesAlphabetically(
57	  machines: MachineMetric[]
58	): MachineMetric[] {
59	  return [...machines].sort((a, b) => {
60	    const nameA = (a.machineId || '').toString();
61	    const nameB = (b.machineId || '').toString();
62	
63	    const matchA = nameA.match(/^(.+?)(\d+)?$/);
64	    const matchB = nameB.match(/^(.+?)(\d+)?$/);
65	
66	    if (!matchA || !matchB) {
67	      return nameA.localeCompare(nameB);
68	    }
69	
70	    const [, baseA, numA] = matchA;
71	    const [, baseB, numB] = matchB;
72	
73	    const baseCompare = baseA.localeCompare(baseB);
74	    if (baseCompare !== 0) {
75	      return baseCompare;
76	    }
77	
78	    const numAInt = numA ? parseInt(numA, 10) : 0;
79	    const numBInt = numB ? parseInt(numB, 10) : 0;
80	
81	    return numAInt - numBInt;
82	  });
83	}
84	
85	// ============================================================================
86	// Main Hook
87	// ============================================================================
88	
89	export function useCollectionReportDetailsData() {
90	  // ==========================================================================
91	  // Navigation & URL State
92	  // ==========================================================================
93	  const params = useParams();
94	  const router = useRouter();
95	  const searchParams = useSearchParams();
96	  const reportId = params.reportId as string;
97	
98	  // ==========================================================================
99	  // Data Loading — resilient fetch with retry, timeout, and countdown
100	  // ==========================================================================
101	  // Load the report (required) and its collections (best-effort) together so the
102	  // page has a single retryable unit. A collections-only failure falls back to []
103	  // and does NOT fail the whole load — only the report fetch drives error state.
104	  const loadReportData = useCallback(
105	    async (signal: AbortSignal) => {
106	      const config = { signal, timeout: ATTEMPT_TIMEOUT_MS };
107	      const [report, collectionsData] = await Promise.all([
108	        fetchCollectionReportById(reportId, config),
109	        fetchCollectionsByLocationReportId(reportId, config).catch(
110	          () => [] as CollectionDocument[]
111	        ),
112	      ]);
113	      return { report, collections: collectionsData };
114	    },
115	    [reportId]
116	  );
117	
118	  const {
119	    data: retryData,
120	    error: retryError,
121	    isLoading,
122	    isRetrying,
123	    attempt,
124	    maxRetries,
125	    retryCountdown,
126	    execute: loadAll,
127	  } = useRequestWithRetry(loadReportData, {
128	    attemptTimeoutMs: ATTEMPT_TIMEOUT_MS,
129	  });
130	
131	  const reportData = useMemo<CollectionReportData | null>(() => {
132	    const report = retryData?.report;
133	    if (!report) return null;
134	    return validateCollectionReportData(report) ? report : null;
135	  }, [retryData]);
136	
137	  const collections = useMemo<CollectionDocument[]>(
138	    () => retryData?.collections ?? [],
139	    [retryData]
