141	
142	  // Map low-level retry errors / missing data to the page's error codes.
143	  //   'UNAUTHORIZED' -> access denied screen
144	  //   'CONNECTION'   -> timeout/connection screen (report likely exists; retry)
145	  //   any other string -> genuine "not found" screen
146	  const error = useMemo<string | null>(() => {
147	    if (retryError) {
148	      if (
149	        retryError.status === 403 ||
150	        retryError.message?.includes('Unauthorized')
151	      ) {
152	        return 'UNAUTHORIZED';
153	      }
154	      // Timeout / connection / network / server errors mean the request never finished —
155	      // the report probably DOES exist, so surface a connection error (with retry), not 404.
156	      if (
157	        retryError.isTimeoutError ||
158	        retryError.isConnectionError ||
159	        retryError.isNetworkError ||
160	        retryError.status === 500 ||
161	        retryError.status === 502 ||
162	        retryError.status === 503 ||
163	        retryError.status === 504
164	      ) {
165	        return 'CONNECTION';
166	      }
167	      return 'Failed to fetch report data. Please try again.';
168	    }
169	    if (retryData && !retryData.report) {
170	      return 'Report not found. Please use a valid report ID.';
171	    }
172	    if (
173	      retryData?.report &&
174	      !validateCollectionReportData(retryData.report)
175	    ) {
176	      return 'Invalid report data received from server.';
177	    }
178	    return null;
179	  }, [retryError, retryData]);
180	
181	  // Raw message for the connection-error detail panel.
182	  const errorDetail = retryError?.message ?? null;
183	
184	  // Keep the skeleton up until the first attempt resolves (avoids a NotFound flash).
185	  const loading = isLoading || (!retryData && !retryError);
186	
187	  // ==========================================================================
188	  // Local State - Table Controls
189	  // ==========================================================================
190	  const [machinePage, setMachinePage] = useState(1);
191	  const [sortField, setSortField] = useState<keyof MachineMetric>('sasGross');
192	  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');
193	  const [searchTerm, setSearchTerm] = useState('');
194	
195	  // ==========================================================================
196	  // Local State - Tab Navigation
197	  // ==========================================================================
198	  const [activeTab, setActiveTab] = useState<TabType>(() => {
199	    const section = searchParams?.get('section');
200	    if (section === 'location') return 'Location Metrics';
201	    if (section === 'sas') return 'SAS Metrics Compare';
202	    if (section === 'machine') return 'Machine Metrics';
203	    return 'Machine Metrics';
204	  });
205	
206	  // ==========================================================================
207	  // Refs
208	  // ==========================================================================
209	  const tabContentRef = useRef<HTMLDivElement>(null);
210	
211	  // ==========================================================================
212	  // Computed
213	  // ==========================================================================
214	
215	  /**
216	   * Data sorted by the selected field, with special handling for machine names
217	   */
218	  const filteredAndSortedData = useMemo(() => {
219	    const metricsData = reportData?.machineMetrics || [];
220	    let sorted = [...metricsData];
221	
222	    if (sortField === 'machineId') {
223	      sorted = sortMachinesAlphabetically(metricsData);
224	      if (sortDirection === 'desc') {
225	        sorted = sorted.reverse();
226	      }
227	    } else {
228	      sorted = [...metricsData].sort((a, b) => {
229	        const aValue = a[sortField];
230	        const bValue = b[sortField];
231	
232	        if (typeof aValue === 'number' && typeof bValue === 'number') {
233	          return sortDirection === 'asc' ? aValue - bValue : bValue - aValue;
234	        }
235	
236	        if (typeof aValue === 'string' && typeof bValue === 'string') {
237	          return sortDirection === 'asc'
238	            ? aValue.localeCompare(bValue)
239	            : bValue.localeCompare(aValue);
240	        }
241	
242	        return 0;
243	      });
244	    }
245	
246	    return sorted;
247	  }, [reportData?.machineMetrics, sortField, sortDirection]);
248	
249	  /**
250	   * Data filtered by search term across multiple fields
251	   */
252	  const filteredSortedAndSearchedData = useMemo(() => {
253	    let data = filteredAndSortedData;
254	
255	    if (searchTerm.trim()) {
256	      const lowerSearch = searchTerm.toLowerCase();
257	      data = data.filter(item => {
258	        return (
259	          item.machineId?.toLowerCase().includes(lowerSearch) ||
260	          item.actualMachineId?.toLowerCase().includes(lowerSearch) ||
261	          item.dropCancelled?.toLowerCase().includes(lowerSearch) ||
262	          item.metersGross?.toString().toLowerCase().includes(lowerSearch) ||
263	          item.sasGross?.toString().toLowerCase().includes(lowerSearch)
264	        );
265	      });
266	    }
