268	    return data;
269	  }, [filteredAndSortedData, searchTerm]);
270	
271	  /**
272	   * Total pages for machine metrics pagination
273	   */
274	  const machineTotalPages = useMemo(() => {
275	    const total = Math.ceil(
276	      filteredSortedAndSearchedData.length / ITEMS_PER_PAGE
277	    );
278	    return total > 0 ? total : 1;
279	  }, [filteredSortedAndSearchedData.length]);
280	
281	  /**
282	   * Current page slice of machine metrics
283	   */
284	  const paginatedMetricsData = useMemo(() => {
285	    const startIndex = (machinePage - 1) * ITEMS_PER_PAGE;
286	    const endIndex = startIndex + ITEMS_PER_PAGE;
287	    return filteredSortedAndSearchedData.slice(startIndex, endIndex);
288	  }, [filteredSortedAndSearchedData, machinePage]);
289	
290	  // ==========================================================================
291	  // Handlers
292	  // ==========================================================================
293	
294	  /**
295	   * Handle column header click for sorting
296	   */
297	  const handleSort = (field: keyof MachineMetric) => {
298	    if (sortField === field) {
299	      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
300	    } else {
301	      setSortField(field);
302	      setSortDirection('desc');
303	    }
304	    setMachinePage(1);
305	  };
306	
307	  // ==========================================================================
308	  // Handlers
309	  // ==========================================================================
310	
311	  /**
312	   * Handle tab change and sync with URL
313	   */
314	  const handleTabChange = (tab: TabType) => {
315	    setActiveTab(tab);
316	    const sectionMap: Record<string, string> = {
317	      'Machine Metrics': 'machine',
318	      'Location Metrics': 'location',
319	      'SAS Metrics Compare': 'sas',
320	    };
321	
322	    const urlParams = new URLSearchParams(searchParams?.toString() || '');
323	    urlParams.set('section', sectionMap[tab]);
324	    const newUrl = `/collection-report/report/${reportId}?${urlParams.toString()}`;
325	    router.push(newUrl, { scroll: false });
326	  };
327	
328	  // ==========================================================================
329	  // Handlers
330	  // ==========================================================================
331	
332	  /**
333	   * Refresh report and collections data (re-runs the retryable load).
334	   */
335	  const handleRefresh = useCallback(() => {
336	    loadAll();
337	  }, [loadAll]);
338	
339	  // ==========================================================================
340	  // Effects
341	  // ==========================================================================
342	
343	  /**
344	   * Initial data fetch on mount and whenever the report changes.
345	   * `loadAll` is stable; `reportId` re-triggers the load (and aborts the prior one).
346	   */
347	  useEffect(() => {
348	    loadAll();
349	  }, [reportId, loadAll]);
350	
351	  /**
352	   * Reset pagination when search term changes
353	   */
354	  useEffect(() => {
355	    setMachinePage(1);
356	  }, [searchTerm]);
357	
358	  /**
359	   * Sync tab state with URL changes (browser back/forward)
360	   */
361	  useEffect(() => {
362	    const section = searchParams?.get('section');
363	    if (section === 'location' && activeTab !== 'Location Metrics') {
364	      setActiveTab('Location Metrics');
365	    } else if (section === 'sas' && activeTab !== 'SAS Metrics Compare') {
366	      setActiveTab('SAS Metrics Compare');
367	    } else if (section === 'machine' && activeTab !== 'Machine Metrics') {
368	      setActiveTab('Machine Metrics');
369	    } else if (!section && activeTab !== 'Machine Metrics') {
370	      setActiveTab('Machine Metrics');
371	    }
372	  }, [searchParams, activeTab]);
373	
374	  // ==========================================================================
375	  // Return
376	  // ==========================================================================
377	
378	  return {
379	    // State
380	    reportId,
381	    reportData,
382	    loading,
383	    error,
384	    errorDetail,
385	    collections,
386	    // Retry / progress state
387	    isRetrying,
388	    attempt,
389	    maxRetries,
390	    retryCountdown,
391	    machinePage,
392	    activeTab,
393	    searchTerm,
394	    sortField,
395	    sortDirection,
396	    paginatedMetricsData,
397	    machineTotalPages,
398	    tabContentRef,
399	    // Setters
400	    setMachinePage,
401	    setSearchTerm,
402	    // Handlers
403	    handleSort,
404	    handleTabChange,
405	    handleRefresh,
406	  };
407	}
