43	/**
44	 * Main GET handler for fetching an individual collection report
45	 *
46	 * Retrieves a collection report with machine metrics and access control checks.
47	 * Standardizes on supporting both human-readable locationReportId and MongoDB _id.
48	 * The reportId is extracted from the request URL path.
49	 *
50	 * @param {NextRequest} request - Information about the incoming request
51	 *
52	 * Flow:
53	 * 1. Connect to the database
54	 * 2. Parse reportId from URL
55	 * 3. Find report by locationReportId or MongoDB _id
56	 * 4. Verify user has access to the location
57	 * 5. Fetch user session
58	 * 6. Fetch enriched report data using helper
59	 * 7. Handle missing collectionDate fallback
60	 * 8. Return report data
61	 */
62	export async function GET(request: NextRequest): Promise<NextResponse> {
63	  const startTime = Date.now();
64	  const functionName = 'GET /api/collection-reports/[reportId]';
65	  const user = extractUserFromRequest(request);
66	  logRouteRequest(functionName, 'GET', request.nextUrl.pathname, user);
67	
68	  try {
69	    // ============================================================================
70	    // STEP 1: Connect to the database
71	    // ============================================================================
72	    await connectDB();
73	    logRoutePhase(functionName, 'db connected', Date.now() - startTime);
74	
75	    // ============================================================================
76	    // STEP 2: Parse reportId from URL
77	    // ============================================================================
78	    const reportId = request.nextUrl.pathname.split('/').pop();
79	
80	    if (!reportId) {
81	      logRouteError(
82	        functionName,
83	        'GET',
84	        '/api/collection-reports/[reportId]',
85	        'Report ID is required',
86	        user
87	      );
88	      return NextResponse.json(
89	        { message: 'Report ID is required' },
90	        { status: 400 }
91	      );
92	    }
93	
94	    // ============================================================================
95	    // STEP 3: Find report by locationReportId or MongoDB _id
96	    // ============================================================================
97	    let report = await CollectionReport.findOne({
98	      locationReportId: reportId,
99	    }).lean<CollectionReportDocument | null>();
100	
101	    if (!report) {
102	      report = await CollectionReport.findOne({
103	        _id: reportId,
104	      }).lean<CollectionReportDocument | null>();
105	    }
106	
107	    if (!report) {
108	      logRouteError(
109	        functionName,
110	        'GET',
111	        '/api/collection-reports/[reportId]',
112	        'Collection Report not found',
113	        user
114	      );
115	      return NextResponse.json(
116	        { message: 'Collection Report not found' },
117	        { status: 404 }
118	      );
119	    }
120	
121	    // ============================================================================
122	    // STEP 4: Verify user has access to the location
123	    // ============================================================================
124	    if (report.location) {
125	      const hasAccess = await checkUserLocationAccess(report.location);
126	      if (!hasAccess) {
127	        logRouteError(
128	          functionName,
129	          'GET',
130	          '/api/collection-reports/[reportId]',
131	          'Unauthorized: location access denied',
132	          user
133	        );
134	        return NextResponse.json(
135	          {
136	            message:
137	              "Unauthorized: You do not have access to this collection report's location",
138	          },
139	          { status: 403 }
140	        );
141	      }
142	    }
143	
144	    // ============================================================================
145	    // STEP 5: Fetch user session
146	    // ============================================================================
147	    const currentUser = await getUserFromServer();
148	    if (!currentUser) {
149	      logRouteError(
150	        functionName,
151	        'GET',
152	        '/api/collection-reports/[reportId]',
153	        'User not found',
154	        user
155	      );
156	      return NextResponse.json({ message: 'User not found' }, { status: 404 });
157	    }
158	
159	    // ============================================================================
160	    // STEP 6: Fetch enriched report data using helper
161	    // ============================================================================
162	    logRoutePhase(
163	      functionName,
164	      'enriching report data — start',
165	      Date.now() - startTime
166	    );
167	    const reportData = await getCollectionReportById(
168	      (report.locationReportId as string) || reportId,
169	      currentUser as Parameters<typeof getCollectionReportById>[1],
170	      report
171	    );
172	    logRoutePhase(
173	      functionName,
174	      'enriching report data — done',
175	      Date.now() - startTime
176	    );
177	
178	    if (!reportData) {
179	      return NextResponse.json(
180	        { message: 'Collection Report not found' },
181	        { status: 404 }
182	      );
183	    }
184	
185	    // ============================================================================
186	    // STEP 7: Handle missing collectionDate fallback
187	    // ============================================================================
188	    if (!reportData.collectionDate && report.timestamp) {
189	      reportData.collectionDate = new Date(report.timestamp).toISOString();
190	    }
191	
192	    // ============================================================================
193	    // STEP 8: Return report data
194	    // ============================================================================
195	    const duration = Date.now() - startTime;
196	    logRouteFetch(
197	      functionName,
198	      'GET',
199	      '/api/collection-reports/[reportId]',
200	      1,
201	      user,
202	      duration
203	    );
204	    return NextResponse.json(reportData);
205	  } catch (error: unknown) {
206	    console.error(`[GET /api/collection-reports/[reportId]] Error:`, error);
207	    const errorMessage =
208	      error instanceof Error ? error.message : 'Internal server error';
209	    logRouteError(
210	      functionName,
211	      'GET',
212	      '/api/collection-reports/[reportId]',
213	      errorMessage,
214	      user
215	    );
216	    return NextResponse.json({ message: errorMessage }, { status: 500 });
217	  }
218	}
