220	/**
221	 * Main PATCH handler for updating an individual collection report
222	 *
223	 * Updates a collection report and cascades changes to related collections.
224	 * The reportId is extracted from the request URL path.
225	 *
226	 * @param {NextRequest} request - Information about the incoming request
227	 * @body {Partial<CreateCollectionReportPayload>} updateData - Fields to update (amountCollected, etc.)
228	 *
229	 * Flow:
230	 * 1. Connect to the database
231	 * 2. Parse reportId from URL and request body
232	 * 3. Find existing report (handle either ID type)
233	 * 4. Fetch associated collections to track machine list changes
234	 * 5. Update using specialized helper
235	 * 6. Log activity
236	 * 7. Return success response
237	 */
238	export async function PATCH(request: NextRequest): Promise<NextResponse | Response> {
239	  const startTime = Date.now();
240	  const functionName = 'PATCH /api/collection-reports/[reportId]';
241	  const user = extractUserFromRequest(request);
242	
243	  try {
244	    // ============================================================================
245	    // STEP 1: Connect to the database
246	    // ============================================================================
247	    await connectDB();
248	
249	    // ============================================================================
250	    // STEP 2: Parse reportId from URL and request body
251	    // ============================================================================
252	    const reportId = request.nextUrl.pathname.split('/').pop();
253	
254	    if (!reportId) {
255	      logRouteError(
256	        functionName,
257	        'PATCH',
258	        '/api/collection-reports/[reportId]',
259	        'Report ID is required',
260	        user
261	      );
262	      return NextResponse.json(
263	        { message: 'Report ID is required' },
264	        { status: 400 }
265	      );
266	    }
267	
268	    const body =
269	      (await request.json()) as Partial<CreateCollectionReportPayload>;
270	
271	    // CRITICAL: Do not update the collector field during edit
272	    delete body.collector;
273	    delete body.collectorName;
274	
275	    // ============================================================================
276	    // STEP 3: Find existing report (handle either ID type)
277	    // ============================================================================
278	    let existingReport = await CollectionReport.findOne({
279	      locationReportId: reportId,
280	    });
281	    if (!existingReport) {
282	      existingReport = await CollectionReport.findOne({ _id: reportId });
283	    }
284	
285	    if (!existingReport) {
286	      return NextResponse.json(
287	        { message: 'Collection Report not found' },
288	        { status: 404 }
289	      );
290	    }
291	
292	    const resolvedReportId = existingReport.locationReportId || reportId;
293	
294	    // ============================================================================
295	    // STEP 4–7: Stream SSE phases while updating the report
296	    // ============================================================================
297	    const ipAddress = getClientIP(request) || undefined;
298	    const userAgent = request.headers.get('user-agent');
299	
300	    return createSseResponse(async send => {
301	      // Fetch existing collections for activity logging
302	      send({ type: 'phase', phase: 'fetching' });
303	      logRoutePhase(functionName, 'fetching existing collections', Date.now() - startTime);
304	      const existingCollections = await Collections.find({
305	        locationReportId: resolvedReportId,
306	      }).lean<CollectionDocument[]>();
307	
308	      // Update — helper emits saving / recalculating / variation
309	      logRoutePhase(functionName, 'updating report — start', Date.now() - startTime);
310	      const updateResult = await updateCollectionReport(
311	        resolvedReportId,
312	        body,
313	        phase => send({ type: 'phase', phase }),
314	        (phase, done, total, machineName) =>
315	          send({ type: 'progress', phase, done, total, machineName })
316	      );
317	
318	      if (!updateResult.success) {
319	        send({ type: 'error', message: updateResult.error || 'Failed to update collection report' });
320	        return;
321	      }
322	      logRoutePhase(functionName, 'updating report — done', Date.now() - startTime);
323	
324	      // Log activity
325	      send({ type: 'phase', phase: 'activity' });
326	      logRoutePhase(functionName, 'recording activity', Date.now() - startTime);
327	      const currentUser = await getUserFromServer();
328	      if (currentUser && currentUser.emailAddress) {
329	        await logCRPatchActivity({
330	          existingReport,
331	          existingCollections,
332	          body,
333	          resolvedReportId,
334	          ipAddress,
335	          userAgent,
336	          currentUser: { _id: currentUser._id, emailAddress: currentUser.emailAddress },
337	        });
338	      }
339	
340	      const duration = Date.now() - startTime;
341	      logRouteUpdate(
342	        functionName,
343	        'PATCH',
344	        '/api/collection-reports/[reportId]',
345	        1,
346	        user,
347	        duration
348	      );
349	      send({ type: 'done', data: { success: true, data: updateResult.data } });
350	    });
351	  } catch (error: unknown) {
352	    console.error(`[PATCH /api/collection-reports/[reportId]] Error:`, error);
353	    const errorMessage =
354	      error instanceof Error ? error.message : 'Internal server error';
355	    logRouteError(
356	      functionName,
357	      'PATCH',
358	      '/api/collection-reports/[reportId]',
359	      errorMessage,
360	      user
361	    );
362	    return NextResponse.json({ message: errorMessage }, { status: 500 });
363	  }
364	}
