422	    if (!deleteRoles.some(role => userRoles.includes(role))) {
423	      return NextResponse.json(
424	        { success: false, error: 'Insufficient permissions to delete report' },
425	        { status: 403 }
426	      );
427	    }
428	
429	    // ============================================================================
430	    // STEP 3: Find existing report
431	    // ============================================================================
432	    let existingReport = await CollectionReport.findOne({
433	      locationReportId: reportId,
434	    }).lean<CollectionReportDocument | null>();
435	    if (!existingReport) {
436	      existingReport = await CollectionReport.findOne({ _id: reportId });
437	    }
438	
439	    if (!existingReport) {
440	      logRouteError(
441	        functionName,
442	        'DELETE',
443	        '/api/collection-reports/[reportId]',
444	        'Collection Report not found',
445	        user
446	      );
447	      return NextResponse.json(
448	        { message: 'Collection Report not found' },
449	        { status: 404 }
450	      );
451	    }
452	
453	    const resolvedReportId = existingReport.locationReportId || reportId;
454	
455	    // ============================================================================
456	    // STEP 4–11: Stream SSE phases while deleting the report
457	    // ============================================================================
458	    const ipAddress = getClientIP(request) || undefined;
459	    const userAgent = request.headers.get('user-agent');
460	
461	    return createSseResponse(async send => {
462	      // Fetch collections
463	      send({ type: 'phase', phase: 'fetching' });
464	      logRoutePhase(functionName, 'fetching collections', Date.now() - startTime);
465	      const associatedCollections = await Collections.find({
466	        locationReportId: resolvedReportId,
467	      }).lean<CollectionDocument[]>();
468	      logRoutePhase(functionName, `found ${associatedCollections.length} collections`, Date.now() - startTime);
469	
470	      // Remove meter records
471	      send({ type: 'phase', phase: 'meters' });
472	      logRoutePhase(functionName, 'removing meter records', Date.now() - startTime);
473	      const deleteMetersResult = await deleteManualMetersPerCollection(resolvedReportId);
474	      if (!deleteMetersResult.success) {
475	        send({ type: 'error', message: deleteMetersResult.error || 'Failed to delete manual meters' });
476	        return;
477	      }
478	      logRoutePhase(functionName, 'meter records removed', Date.now() - startTime);
479	
480	      // Delete collections
481	      send({ type: 'phase', phase: 'collections' });
482	      logRoutePhase(functionName, 'deleting collections', Date.now() - startTime);
483	      const deleteResult = await Collections.deleteMany({ locationReportId: resolvedReportId });
484	      if (deleteResult.deletedCount === 0) {
485	        console.warn(`[DELETE] No collections deleted for report ${resolvedReportId}`);
486	      }
487	      logRoutePhase(functionName, `deleted ${deleteResult.deletedCount} collections`, Date.now() - startTime);
488	
489	      // Delete report document
490	      logRoutePhase(functionName, 'deleting report document', Date.now() - startTime);
491	      const deletedReport = await CollectionReport.findOneAndDelete({ _id: existingReport._id });
492	      if (!deletedReport) {
493	        send({ type: 'error', message: 'Failed to delete collection report' });
494	        return;
495	      }
496	      logRoutePhase(functionName, 'report document deleted', Date.now() - startTime);
497	
498	      // Propagate deletion forward
499	      send({ type: 'phase', phase: 'propagating' });
500	      logRoutePhase(functionName, 'updating linked reports — start', Date.now() - startTime);
501	      await propagateCRDeletionForward(associatedCollections);
502	      logRoutePhase(functionName, 'updating linked reports — done', Date.now() - startTime);
503	
504	      // Log activity
505	      send({ type: 'phase', phase: 'activity' });
506	      logRoutePhase(functionName, 'recording activity', Date.now() - startTime);
507	      if (currentUser) {
508	        await logCRDeletionActivity({
509	          existingReport: existingReport as CollectionReportDocument,
510	          associatedCollections,
511	          resolvedReportId,
512	          ipAddress,
513	          userAgent,
514	          currentUser: { _id: currentUser._id, emailAddress: currentUser.emailAddress },
515	        });
516	      }
517	      logRoutePhase(functionName, 'activity recorded', Date.now() - startTime);
518	
519	      const duration = Date.now() - startTime;
520	      logRouteDelete(
521	        functionName,
522	        'DELETE',
523	        '/api/collection-reports/[reportId]',
524	        1,
525	        user,
526	        duration
527	      );
528	      send({ type: 'done', data: { success: true, message: 'Collection report deleted successfully' } });
529	    });
530	  } catch (error: unknown) {
531	    console.error(`[DELETE /api/collection-reports/[reportId]] Error:`, error);
532	    const errorMessage =
533	      error instanceof Error ? error.message : 'Internal server error';
534	    logRouteError(
535	      functionName,
536	      'DELETE',
537	      '/api/collection-reports/[reportId]',
538	      errorMessage,
539	      user
540	    );
541	    return NextResponse.json({ message: errorMessage }, { status: 500 });
542	  }
543	}
