83	/**
84	 * Handles RAM clear toggle for the collection-by-ID PATCH route. Only processes
85	 * the toggle for non-relay machines (relay machines have SMIB-managed meters).
86	 *
87	 * @param {CollectionDocument} originalCollection - The existing collection being updated
88	 * @param {Record<string, unknown>} updateData - The update payload (mutated in place)
89	 * @param {string | Date | undefined} explicitSasEndTime - Explicit SAS end time for readAt
90	 * @returns {Promise<RamClearToggleResult>} Fields to $unset on the collection document
91	 */
92	export async function handleRamClearToggleWithRelayGuard(
93	  originalCollection: CollectionDocument,
94	  updateData: Record<string, unknown>,
95	  explicitSasEndTime: string | Date | undefined
96	): Promise<RamClearToggleResult> {
97	  if (!originalCollection) {
98	    console.error('[handleRamClearToggleWithRelayGuard] originalCollection is required');
99	    return { unsetData: {} };
100	  }
101	  if (!updateData) {
102	    console.error('[handleRamClearToggleWithRelayGuard] updateData is required');
103	    return { unsetData: {} };
104	  }
105	
106	  const ramClearChanged =
107	    updateData.ramClear !== undefined &&
108	    updateData.ramClear !== originalCollection.ramClear;
