110	  if (!ramClearChanged) {
111	    return { unsetData: {} };
112	  }
113	
114	  const hasRelay = originalCollection.machineId
115	    ? await checkMachineHasRelay(originalCollection.machineId)
116	    : false;
117	
118	  if (hasRelay) {
119	    return { unsetData: {} };
120	  }
121	
122	  return handleRamClearToggle(
