130	// ============================================================================
131	// SAS Time Field Extraction
132	// ============================================================================
133	
134	/**
135	 * Extracts SAS time fields from the update payload and removes them from the
136	 * top-level data to prevent Mongoose strict-mode from silently dropping them.
137	 * Also strips collector/collectorName to prevent ownership reassignment.
138	 *
139	 * @param {Record<string, unknown>} safeUpdateData - The update payload (mutated: SAS fields removed)
140	 * @returns {SasTimeExtractionResult} Extracted SAS time values and presence flags
141	 */
142	export function extractSasTimeFieldsFromPayload(
143	  safeUpdateData: Record<string, unknown>
144	): SasTimeExtractionResult {
145	  const payloadSasEndTime = safeUpdateData.sasEndTime as string | Date | undefined;
146	  const payloadSasStartTime = safeUpdateData.sasStartTime as string | Date | undefined;
147	
148	  delete safeUpdateData.sasEndTime;
149	  delete safeUpdateData.sasStartTime;
150	  delete safeUpdateData.collector;
151	  delete safeUpdateData.collectorName;
152	
153	  return {
154	    payloadSasEndTime,
155	    payloadSasStartTime,
156	    hasPayloadSasEndTime: payloadSasEndTime !== undefined,
157	    hasPayloadSasStartTime: payloadSasStartTime !== undefined,
158	  };
159	}
