161	// ============================================================================
162	// Recalculation Flags
163	// ============================================================================
164	
165	/**
166	 * Determines which recalculation steps are needed based on the update payload.
167	 *
168	 * @param {Record<string, unknown>} updateData - The raw update payload
169	 * @param {SasTimeExtractionResult} sasFields - Extracted SAS time field flags
170	 * @returns {RecalculationFlags} Flags indicating which recalculations to perform
171	 */
172	export function determineRecalculationFlags(
173	  updateData: Record<string, unknown>,
174	  sasFields: SasTimeExtractionResult
175	): RecalculationFlags {
176	  const shouldRecalculate =
177	    updateData.metersIn !== undefined ||
178	    updateData.metersOut !== undefined ||
179	    updateData.timestamp !== undefined ||
180	    updateData.collectionTime !== undefined ||
181	    updateData.ramClear !== undefined ||
182	    updateData.ramClearMetersIn !== undefined ||
183	    updateData.ramClearMetersOut !== undefined ||
184	    updateData.ramClearCoinIn !== undefined ||
185	    updateData.ramClearCoinOut !== undefined;
186	
187	  const hasTimestampChange = updateData.timestamp !== undefined;
188	  const needsSasTimeRecalculation =
189	    hasTimestampChange && !sasFields.hasPayloadSasStartTime && !sasFields.hasPayloadSasEndTime;
190	
191	  return { shouldRecalculate, hasTimestampChange, needsSasTimeRecalculation };
192	}
193	
194	// ============================================================================
195	// SAS Time Resolution
196	// ============================================================================
197	
198	function toDateSafe(val: Date | string | undefined): Date {
199	  if (!val) return new Date();
200	  return typeof val === 'string' ? new Date(val) : val;
201	}
202	
203	function toSafeDateWithFallback(
204	  val: Date | string | undefined,
205	  fallback: Date | string | undefined
206	): Date {
207	  if (val) return typeof val === 'string' ? new Date(val) : val;
208	  if (fallback) return typeof fallback === 'string' ? new Date(fallback) : fallback;
209	  return new Date();
210	}
211	
212	/**
213	 * Resolves SAS time range based on 4 priority cases:
214	 * 1. Both SAS times explicitly provided
215	 * 2. Only sasEndTime provided (simple mode) - calculates sasStartTime
216	 * 3. Timestamp changed - recalculates both SAS times and metrics
217	 * 4. No changes - keeps existing times
218	 *
219	 * @param {CollectionDocument} updatedCollection - The collection after first update
220	 * @param {SasTimeExtractionResult} sasFields - Extracted SAS time fields
221	 * @param {RecalculationFlags} flags - Recalculation flags
222	 * @param {Record<string, unknown>} updateData - The raw update payload
223	 * @returns {Promise<{ finalSasStartTime: Date; finalSasEndTime: Date; sasMetersData: Record<string, unknown> | null }>}
224	 */
225	async function resolveSasTimeRange(
226	  updatedCollection: CollectionDocument,
227	  sasFields: SasTimeExtractionResult,
228	  flags: RecalculationFlags,
229	  updateData: Record<string, unknown>
230	): Promise<{
231	  finalSasStartTime: Date;
232	  finalSasEndTime: Date;
233	  sasMetersData: Record<string, unknown> | null;
234	}> {
235	  if (!updatedCollection.sasMeters) {
236	    return {
237	      finalSasStartTime: new Date(),
238	      finalSasEndTime: new Date(),
239	      sasMetersData: null,
240	    };
241	  }
242	
243	  const existingSasMeters = updatedCollection.sasMeters;
244	  let sasMetersData: Record<string, unknown> = {
245	    ...existingSasMeters,
246	    machine: existingSasMeters.machine || updatedCollection.machineName || '',
247	    jackpot: Number((existingSasMeters.jackpot || 0).toFixed(2)),
248	    gamesPlayed: existingSasMeters.gamesPlayed || 0,
249	  };
250	
251	  const fallbackTime = updatedCollection.collectionTime || updatedCollection.timestamp;
252	  let finalSasStartTime = toSafeDateWithFallback(
253	    existingSasMeters?.sasStartTime as Date | undefined,
254	    fallbackTime
255	  );
256	  let finalSasEndTime = toSafeDateWithFallback(
257	    existingSasMeters?.sasEndTime as Date | undefined,
258	    fallbackTime
259	  );
260	
261	  if (sasFields.hasPayloadSasStartTime && sasFields.hasPayloadSasEndTime) {
262	    finalSasStartTime = toDateSafe(sasFields.payloadSasStartTime as string | Date);
263	    finalSasEndTime = toDateSafe(sasFields.payloadSasEndTime as string | Date);
264	
265	    const { calculateSasMetrics } = await import(
266	      '@/app/api/lib/helpers/collectionReport/creation'
267	    );
268	    const newSasMetrics = await calculateSasMetrics(
269	      updatedCollection.machineId,
270	      finalSasStartTime,
271	      finalSasEndTime
272	    );
273	    sasMetersData = { ...sasMetersData, ...newSasMetrics };
274	  } else if (sasFields.hasPayloadSasEndTime) {
275	    const userProvidedEndTime = toDateSafe(sasFields.payloadSasEndTime as string | Date);
276	    const { getSasTimePeriod, calculateSasMetrics } = await import(
277	      '@/app/api/lib/helpers/collectionReport/creation'
278	    );
279	    const { sasStartTime: calculatedStartTime } = await getSasTimePeriod(
280	      updatedCollection.machineId,
281	      undefined,
282	      userProvidedEndTime
283	    );
284	    finalSasStartTime = toDateSafe(calculatedStartTime);
285	    finalSasEndTime = userProvidedEndTime;
286	
287	    const newSasMetrics = await calculateSasMetrics(
288	      updatedCollection.machineId,
289	      finalSasStartTime,
290	      finalSasEndTime
291	    );
292	    sasMetersData = { ...sasMetersData, ...newSasMetrics };
293	  } else if (flags.needsSasTimeRecalculation) {
294	    const newTimestamp = toDateSafe(updateData.timestamp as string | Date);
295	    const { getSasTimePeriod, calculateSasMetrics } = await import(
296	      '@/app/api/lib/helpers/collectionReport/creation'
297	    );
298	    const { sasStartTime: calculatedStartTime, sasEndTime: calculatedEndTime } =
299	      await getSasTimePeriod(updatedCollection.machineId, undefined, newTimestamp);
300	    finalSasStartTime = toDateSafe(calculatedStartTime);
301	    finalSasEndTime = toDateSafe(calculatedEndTime);
302	
303	    const newSasMetrics = await calculateSasMetrics(
304	      updatedCollection.machineId,
305	      finalSasStartTime,
306	      finalSasEndTime
307	    );
308	    sasMetersData = { ...sasMetersData, ...newSasMetrics };
309	  }
310	
311	  sasMetersData.sasStartTime = finalSasStartTime;
312	  sasMetersData.sasEndTime = finalSasEndTime;
313	
314	  return { finalSasStartTime, finalSasEndTime, sasMetersData };
315	}
316	
317	// ============================================================================
318	// Movement and SAS Recalculation
319	// ============================================================================
320	
321	/**
322	 * Recalculates movement and SAS metrics for a collection after the first update.
323	 * Handles movement calculation, soft meters, SAS time resolution (4 cases),
324	 * applies the second update, and triggers post-update propagation.
325	 *
326	 * @param {string} collectionId - The collection ID being updated
327	 * @param {CollectionDocument} updatedCollection - The collection after first update
328	 * @param {Record<string, unknown>} updateData - The raw update payload
329	 * @param {SasTimeExtractionResult} sasFields - Extracted SAS time fields
330	 * @param {RecalculationFlags} flags - Recalculation flags
331	 * @returns {Promise<CollectionDocument | null>} The final updated collection, or null if not found
332	 */
333	export async function recalculateMovementAndSasForPatch(
334	  collectionId: string,
335	  updatedCollection: CollectionDocument,
336	  updateData: Record<string, unknown>,
337	  sasFields: SasTimeExtractionResult,
338	  flags: RecalculationFlags
339	): Promise<CollectionDocument | null> {
340	  if (!collectionId) {
341	    console.error('[recalculateMovementAndSasForPatch] collectionId is required');
342	    return null;
343	  }
344	  if (!updatedCollection) {
345	    console.error('[recalculateMovementAndSasForPatch] updatedCollection is required');
346	    return null;
347	  }
348	
349	  const previousMeters: PreviousCollectionMeters = {
350	    metersIn:
351	      updateData.prevIn !== undefined
352	        ? (updateData.prevIn as number)
353	        : updatedCollection.prevIn || 0,
354	    metersOut:
355	      updateData.prevOut !== undefined
356	        ? (updateData.prevOut as number)
357	        : updatedCollection.prevOut || 0,
358	  };
359	
360	  const movement = calculateMovement(
361	    updatedCollection.metersIn || 0,
362	    updatedCollection.metersOut || 0,
363	    previousMeters,
364	    updatedCollection.ramClear,
365	    undefined,
366	    undefined,
367	    updatedCollection.ramClearMetersIn,
368	    updatedCollection.ramClearMetersOut
369	  );
370	
371	  const roundedMovement = {
372	    metersIn: Number(movement.metersIn.toFixed(2)),
373	    metersOut: Number(movement.metersOut.toFixed(2)),
374	    gross: Number(movement.gross.toFixed(2)),
375	  };
376	
377	  const softMetersIn =
378	    updatedCollection.ramClear && updatedCollection.ramClearMetersIn
379	      ? updatedCollection.ramClearMetersIn
380	      : updatedCollection.metersIn || 0;
381	
382	  const softMetersOut =
383	    updatedCollection.ramClear && updatedCollection.ramClearMetersOut
384	      ? updatedCollection.ramClearMetersOut
385	      : updatedCollection.metersOut || 0;
386	
387	  const recalculatedData: Record<string, unknown> = {
388	    movement: roundedMovement,
389	    softMetersIn,
390	    softMetersOut,
391	    updatedAt: new Date(),
392	  };
393	
394	  if (updatedCollection.sasMeters) {
395	    const { sasMetersData } = await resolveSasTimeRange(
396	      updatedCollection,
397	      sasFields,
398	      flags,
399	      updateData
400	    );
401	
402	    if (sasMetersData) {
403	      recalculatedData.sasMeters = sasMetersData;
404	    }
405	  }
406	
407	  const finalUpdatedCollection = await Collections.findOneAndUpdate(
408	    { _id: collectionId },
409	    { $set: recalculatedData },
410	    { new: true, runValidators: true }
411	  );
412	
413	  if (finalUpdatedCollection) {
414	    await updateRegularAndRamClearMeters(finalUpdatedCollection);
415	
416	    try {
417	      const { propagateMetersToNextReport } = await import(
418	        '@/app/api/lib/helpers/collectionReport/reportCreation'
419	      );
420	      await propagateMetersToNextReport(
421	        String(finalUpdatedCollection.machineId),
422	        String(finalUpdatedCollection.location),
423	        finalUpdatedCollection.collectionTime ||
424	          finalUpdatedCollection.timestamp ||
425	          new Date(),
426	        finalUpdatedCollection.metersIn || 0,
427	        finalUpdatedCollection.metersOut || 0
428	      );
429	    } catch (propagateError) {
430	      console.error(
431	        '[recalculateMovementAndSasForPatch] Failed to propagate meters:',
432	        propagateError instanceof Error ? propagateError.message : 'Unknown error'
433	      );
434	    }
435	  }
436	
437	  return finalUpdatedCollection;
438	}
439	
440	// ============================================================================
441	// Machine Collection History Update
442	// ============================================================================
443	
444	/**
445	 * Updates the machine's collectionMetersHistory entry when meters are changed
446	 * during a collection PATCH. Looks up the previous collection for correct
447	 * prevMetersIn/prevMetersOut values, then updates via arrayFilters.
448	 *
449	 * @param {CollectionDocument} updatedCollection - The updated collection document
450	 * @param {Record<string, unknown>} updateData - The raw update payload
451	 * @returns {Promise<void>}
452	 */
453	export async function updateMachineHistoryForPatch(
454	  updatedCollection: CollectionDocument,
455	  updateData: Record<string, unknown>
456	): Promise<void> {
457	  if (!updatedCollection) {
458	    console.error('[updateMachineHistoryForPatch] updatedCollection is required');
459	    return;
460	  }
461	
462	  const metersChanged =
463	    updateData.metersIn !== undefined || updateData.metersOut !== undefined;
464	
465	  if (!updatedCollection.machineId || !metersChanged) {
466	    return;
467	  }
468	
469	  try {
470	    const currentMachine = await Machine.findOne({
471	      _id: updatedCollection.machineId,
472	    }).lean<GamingMachine | null>();
473	
474	    if (!currentMachine) return;
475	
476	    type HistoryEntry = {
477	      locationReportId: string;
478	      prevMetersIn?: number;
479	      prevMetersOut?: number;
480	      metersIn?: number;
481	      metersOut?: number;
482	      timestamp?: Date;
483	    };
484	
485	    const historyEntries = (
486	      currentMachine as GamingMachine & {
487	        collectionMetersHistory?: HistoryEntry[];
488	      }
489	    ).collectionMetersHistory;
490	
491	    const existingHistoryEntry = historyEntries?.find(
492	      (entry: HistoryEntry) =>
493	        entry.locationReportId === updatedCollection.locationReportId
494	    );
495	
496	    if (!existingHistoryEntry) return;
497	
498	    const collectionTimeForComparison =
499	      updatedCollection.collectionTime || updatedCollection.timestamp;
500	
501	    // Priority 1: unified collectionMetersHistory — most recent entry before this
502	    const historyBeforeThis = (historyEntries ?? [])
503	      .filter(
504	        entry =>
505	          entry.timestamp &&
506	          collectionTimeForComparison &&
507	          new Date(entry.timestamp).getTime() <
508	            new Date(collectionTimeForComparison).getTime()
509	      )
510	      .sort(
511	        (a, b) =>
512	          new Date(b.timestamp!).getTime() -
513	          new Date(a.timestamp!).getTime()
514	      );
515	
516	    const previousHistoryEntry = historyBeforeThis[0];
517	
518	    // Priority 2: V1 Collections (backward compat)
519	    const previousCollection = await Collections.findOne(
520	      {
521	        machineId: updatedCollection.machineId,
522	        $or: [
523	          { collectionTime: { $lt: collectionTimeForComparison } },
524	          { timestamp: { $lt: collectionTimeForComparison } },
525	        ],
526	        deletedAt: { $exists: false },
527	      },
528	      {
529	        sort: {
530	          collectionTime: -1,
