625	
626	type TrackedField = {
627	  key: string;
628	  label: string;
629	  getValue: (doc: Record<string, unknown>) => unknown;
630	};
631	
632	const TRACKED_FIELDS: TrackedField[] = [
633	  { key: 'metersIn', label: 'metersIn', getValue: (doc) => doc.metersIn },
634	  { key: 'metersOut', label: 'metersOut', getValue: (doc) => doc.metersOut },
635	  { key: 'prevIn', label: 'prevIn', getValue: (doc) => doc.prevIn },
636	  { key: 'prevOut', label: 'prevOut', getValue: (doc) => doc.prevOut },
637	  { key: 'notes', label: 'notes', getValue: (doc) => doc.notes },
638	  { key: 'ramClear', label: 'ramClear', getValue: (doc) => doc.ramClear },
639	  {
640	    key: 'ramClearMetersIn',
641	    label: 'ramClearMetersIn',
642	    getValue: (doc) => doc.ramClearMetersIn,
643	  },
644	  {
645	    key: 'ramClearMetersOut',
646	    label: 'ramClearMetersOut',
647	    getValue: (doc) => doc.ramClearMetersOut,
648	  },
649	  { key: 'timestamp', label: 'timestamp', getValue: (doc) => doc.timestamp },
650	  {
651	    key: 'collectionTime',
652	    label: 'collectionTime',
653	    getValue: (doc) => doc.collectionTime,
654	  },
655	  {
656	    key: 'sasStartTime',
657	    label: 'sasStartTime',
658	    getValue: (doc) => (doc.sasMeters as Record<string, unknown>)?.sasStartTime,
659	  },
660	  {
661	    key: 'sasEndTime',
662	    label: 'sasEndTime',
663	    getValue: (doc) => (doc.sasMeters as Record<string, unknown>)?.sasEndTime,
664	  },
665	];
666	
667	function isDifferentValue(oldVal: unknown, newVal: unknown): boolean {
668	  if (oldVal === newVal) return false;
669	  if (oldVal == null || newVal == null) {
670	    return (oldVal == null) !== (newVal == null);
671	  }
672	
673	  const isDateLike = (val: unknown): boolean => {
674	    if (val instanceof Date) return true;
675	    if (typeof val === 'string') {
676	      const parsed = Date.parse(val);
677	      return !isNaN(parsed) && val.includes('-');
678	    }
679	    return false;
680	  };
681	
682	  if (isDateLike(oldVal) || isDateLike(newVal)) {
683	    try {
684	      const firstTime = new Date(oldVal as string | number | Date).getTime();
685	      const secondTime = new Date(newVal as string | number | Date).getTime();
686	      if (!isNaN(firstTime) && !isNaN(secondTime)) return firstTime !== secondTime;
687	    } catch {
688	      // fall through
689	    }
690	  }
691	  if (typeof oldVal === 'number' || typeof newVal === 'number') {
692	    return Number(oldVal) !== Number(newVal);
693	  }
694	  if (typeof oldVal === 'boolean' || typeof newVal === 'boolean') {
695	    return Boolean(oldVal) !== Boolean(newVal);
696	  }
697	  if (typeof oldVal === 'string' && typeof newVal === 'string') {
698	    return oldVal.trim() !== newVal.trim();
699	  }
700	  return String(oldVal).trim() !== String(newVal).trim();
701	}
