703	/**
704	 * Logs activity for a collection PATCH with detailed field-level change tracking.
705	 * Compares original collection values against the update payload to produce
706	 * a structured change log.
707	 *
708	 * @param {NextRequest} request - The incoming request (for IP/user-agent extraction)
709	 * @param {CollectionDocument} updatedCollection - The collection after update
710	 * @param {Record<string, unknown> | null} originalCollectionDoc - The original collection as plain object
711	 * @param {Record<string, unknown>} updateData - The raw update payload
712	 * @param {CollectionDocument | null} finalUpdatedCollection - The final collection after recalculation
713	 * @param {string} collectionId - The collection ID
714	 * @returns {Promise<void>}
715	 */
716	export async function logCollectionPatchActivity(
717	  request: NextRequest,
718	  updatedCollection: CollectionDocument,
719	  originalCollectionDoc: Record<string, unknown> | null,
720	  updateData: Record<string, unknown>,
721	  finalUpdatedCollection: CollectionDocument | null,
722	  collectionId: string
723	): Promise<void> {
724	  if (!request) {
725	    console.error('[logCollectionPatchActivity] request is required');
726	    return;
727	  }
728	  if (!updatedCollection) {
729	    console.error('[logCollectionPatchActivity] updatedCollection is required');
730	    return;
731	  }
732	  if (!collectionId) {
733	    console.error('[logCollectionPatchActivity] collectionId is required');
734	    return;
735	  }
736	
737	  const currentUser = await getUserFromServer();
738	  if (!currentUser?.emailAddress) return;
739	
740	  try {
741	    const updateChanges: Array<{
742	      field: string;
743	      oldValue: unknown;
744	      newValue: unknown;
745	    }> = [];
746	
747	    for (const trackedField of TRACKED_FIELDS) {
748	      const newValue = updateData[trackedField.key];
749	      if (newValue === undefined || !originalCollectionDoc) continue;
750	
751	      const oldValue = trackedField.getValue(originalCollectionDoc);
752	      if (isDifferentValue(oldValue, newValue)) {
753	        updateChanges.push({
754	          field: trackedField.label,
755	          oldValue,
756	          newValue,
757	        });
758	      }
759	    }
760	
761	    const machineDisplayName =
762	      updatedCollection.serialNumber ||
763	      updatedCollection.machineName ||
764	      updatedCollection.machineId;
765	
766	    const reportSuffix = updatedCollection.locationReportId
767	      ? ` (report: ${updatedCollection.locationReportId})`
768	      : '';
769	
770	    const changeCount = updateChanges.length;
771	    const pluralSuffix = changeCount !== 1 ? 's' : '';
772	
773	    await logActivity({
774	      action: 'UPDATE',
775	      details: `Updated machine ${machineDisplayName} in collection report${reportSuffix} — ${changeCount} change${pluralSuffix}`,
776	      ipAddress: getClientIP(request) || undefined,
777	      userAgent: request.headers.get('user-agent') || undefined,
778	      userId: currentUser._id as string,
779	      username: currentUser.emailAddress as string,
780	      metadata: {
781	        userId: currentUser._id as string,
782	        userEmail: currentUser.emailAddress as string,
783	        userRole: (currentUser.roles as string[])?.[0] || 'user',
784	        resource: 'collection',
785	        resourceId: collectionId,
786	        resourceName:
787	          updatedCollection.serialNumber ||
788	          String(updatedCollection.machineId),
789	        locationReportId: updatedCollection.locationReportId || '',
790	        location: updatedCollection.location || '',
791	        changes: updateChanges,
792	        previousData: originalCollectionDoc,
793	        newData: finalUpdatedCollection,
794	      },
795	    });
796	  } catch (logError) {
797	    console.error(
798	      '[logCollectionPatchActivity] Error:',
799	      logError instanceof Error ? logError.message : 'Unknown error'
800	    );
801	  }
802	}
