103	/**
104	 * Adapter exposing the streaming variation check via the legacy-shaped API the edit
105	 * modal already consumes (checkVariations / variationsData / isChecking / …) plus the
106	 * fields the new VariationCheckPanel needs. `preCreateThenCheck` no longer pre-creates
107	 * meters — finalization handles that — it just runs the check.
108	 */
109	function useEditVariationAdapter() {
110	  const stream = useVariationStreamCheck();
111	  return {
112	    status: stream.status,
113	    done: stream.done,
114	    total: stream.total,
115	    currentMachineName: stream.currentMachineName,
116	    variationsData: stream.result,
117	    error: stream.error,
118	    isChecking: stream.status === 'checking',
119	    checkComplete: stream.status === 'done',
