121	    hasVariations:
122	      stream.status === 'done' ? (stream.result?.hasVariations ?? false) : null,
123	    checkVariations: (locationId: string, machines: EditCheckMachine[]) =>
124	      stream.run(locationId, toEditVCM(machines)),
